import React, { useMemo, useEffect } from 'react';
import { SearchIcon, XMarkIcon, SparklesIcon } from '../../Icons';
import { SmartEditListItem } from './SmartEditListItem';
import { SuggestionItem } from './useSmartEditController';
import { calculateNameSimilarity } from '../../../services/processingService';

interface SmartEditSuggestionsProps {
    searchQuery: string;
    setSearchQuery: (v: string) => void;
    suggestions: SuggestionItem[];
    setSuggestions: (v: SuggestionItem[]) => void;
    loadingAiId: string | null;
    isReverseMode: boolean;
    manualChurchId: string;
    onSelect: (item: SuggestionItem) => void;
    target: any;
    allContributors: any[];
    availableBankTransactions: any[];
    effectiveIgnoreKeywords: string[];
    churches: any[];
    language: any;
}

export const SmartEditSuggestions: React.FC<SmartEditSuggestionsProps> = ({
    searchQuery, setSearchQuery, suggestions, setSuggestions, loadingAiId,
    isReverseMode, manualChurchId, onSelect, target, allContributors,
    availableBankTransactions, effectiveIgnoreKeywords, churches, language
}) => {
    useEffect(() => {
        if (!target) return;
        let items: SuggestionItem[] = [];

        if (isReverseMode) {
            const targetContributor = target.contributor;
            if (!targetContributor) return;
            items = availableBankTransactions.map(res => {
                const tx = res.transaction;
                const score = calculateNameSimilarity(tx.description, targetContributor, effectiveIgnoreKeywords);
                return {
                    id: tx.id, primaryText: tx.cleanedDescription || tx.description,
                    secondaryText: `Extrato • ${tx.date}`, amount: tx.amount, originalRef: res, score, type: 'transaction'
                };
            });
        } else {
            const tx = target.transaction;
            items = allContributors.map(c => {
                let score = calculateNameSimilarity(tx.description, c, effectiveIgnoreKeywords);
                if (manualChurchId && c._churchId === manualChurchId) score += 50; 
                else if (manualChurchId && c._churchId !== manualChurchId) score -= 80;
                return {
                    id: c.id || `c-${Math.random()}`, primaryText: c.cleanedName || c.name,
                    secondaryText: `${c._churchName} • ${c.date || 'S/D'}`,
                    amount: c.amount, originalRef: c, score, type: 'contributor', churchId: c._churchId
                };
            });
        }

        if (searchQuery.trim()) {
            const lq = searchQuery.toLowerCase();
            items = items.filter(i => i.primaryText.toLowerCase().includes(lq) || String(i.amount).includes(lq));
        }

        let final = items.filter(i => i.score > 20 || searchQuery.trim()).sort((a, b) => b.score - a.score).slice(0, 15);

        if (target.suggestion && !searchQuery.trim()) {
            const s = target.suggestion as any;
            const sChurchId = s.church?.id || s._churchId;
            if (!manualChurchId || sChurchId === manualChurchId) {
                const church = churches.find(c => c.id === sChurchId);
                const sugItem: SuggestionItem = {
                    id: s.id || `sug-${Math.random()}`, primaryText: s.cleanedName || s.name,
                    secondaryText: `${church?.name || s._churchName || 'Igreja'} (Match IA)`,
                    amount: s.amount, originalRef: s, score: 200, type: 'contributor', isAiSuggestion: true, churchId: sChurchId
                };
                final = [sugItem, ...final.filter(i => i.id !== s.id)].slice(0, 5);
            }
        }
        setSuggestions(final);
    }, [target, isReverseMode, allContributors, availableBankTransactions, effectiveIgnoreKeywords, manualChurchId, churches, searchQuery, setSuggestions]);

    return (
        <div className="space-y-4">
            <div className="relative">
                <SearchIcon className="w-3 h-3 text-slate-400 absolute top-1/2 left-2.5 -translate-y-1/2" />
                <input type="text" placeholder={isReverseMode ? "Buscar no extrato..." : "Trocar contribuinte..."} value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-8 pr-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-950 text-xs font-medium shadow-sm focus:ring-1 focus:ring-brand-blue outline-none transition-all placeholder:text-slate-400" />
            </div>
            <div>
                <div className="flex items-center justify-between mb-2">
                    <h4 className="text-[9px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1"><SearchIcon className="w-2.5 h-2.5 text-indigo-500" /> {searchQuery ? 'Resultados' : 'Melhores Matches'}</h4>
                    {loadingAiId && <span className="flex items-center gap-1 text-[8px] text-purple-500 animate-pulse font-bold bg-purple-50 px-1.5 py-0.5 rounded-full"><SparklesIcon className="w-2 h-2" /> Analisando...</span>}
                </div>
                {suggestions.length > 0 ? suggestions.map((item, idx) => (
                    <SmartEditListItem key={item.id} item={item} isSuggestion={!searchQuery} index={idx} language={language} onSelect={onSelect} manualChurchId={manualChurchId} />
                )) : !loadingAiId && <div className="text-center py-4 text-slate-400 text-[10px] italic">Nada encontrado.</div>}
            </div>
        </div>
    );
};

import React from 'react';
import { UserIcon, BanknotesIcon, SparklesIcon } from '../../Icons';
import { formatCurrency } from '../../../utils/formatters';
import { SuggestionItem } from './useSmartEditController';

interface SmartEditListItemProps {
    item: SuggestionItem;
    isSuggestion: boolean;
    index: number;
    language: any;
    onSelect: (item: SuggestionItem) => void;
    manualChurchId: string;
}

export const SmartEditListItem: React.FC<SmartEditListItemProps> = ({
    item, isSuggestion, index, language, onSelect, manualChurchId
}) => (
    <button onClick={() => onSelect(item)} className={`w-full text-left p-2 rounded-lg border transition-all duration-200 group flex items-center justify-between mb-1.5 ${item.isAiSuggestion ? 'bg-gradient-to-r from-purple-50 to-indigo-50 dark:from-purple-900/30 border-purple-200 dark:border-purple-700 shadow-sm ring-1 ring-purple-100' : isSuggestion ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800' : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 hover:bg-slate-50'}`}>
        <div className="flex items-center gap-2 overflow-hidden">
            <div className={`p-1.5 rounded-full flex-shrink-0 ${item.isAiSuggestion ? 'bg-purple-100 text-purple-600' : isSuggestion ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-500'}`}>
                {item.isAiSuggestion ? <SparklesIcon className="w-3 h-3 animate-pulse" /> : (item.type === 'contributor' ? <UserIcon className="w-3 h-3" /> : <BanknotesIcon className="w-3 h-3" />)}
            </div>
            <div className="min-w-0">
                <p className={`text-[11px] font-bold truncate leading-tight ${item.isAiSuggestion ? 'text-purple-800 dark:text-purple-200' : isSuggestion ? 'text-indigo-900 dark:text-indigo-100' : 'text-slate-700 dark:text-slate-200'}`}>{item.primaryText}</p>
                <p className={`text-[9px] truncate ${item.isAiSuggestion ? 'text-purple-600 dark:text-purple-400 font-medium' : 'text-slate-500'}`}>{item.secondaryText}</p>
            </div>
        </div>
        <div className="flex items-center gap-2 flex-shrink-0 ml-1">
            {isSuggestion && index === 0 && item.churchId === manualChurchId && (
                <span className="text-[7px] font-black bg-slate-200 dark:bg-slate-700 text-slate-500 dark:text-slate-400 px-1 py-0.5 rounded border border-slate-300 dark:border-slate-600 uppercase">Enter</span>
            )}
            <span className={`text-[10px] font-bold font-mono ${item.isAiSuggestion ? 'text-purple-700 dark:text-purple-300' : isSuggestion ? 'text-indigo-700 dark:text-indigo-300' : 'text-slate-900 dark:text-white'}`}>{formatCurrency(item.amount, language)}</span>
        </div>
    </button>
);

import React, { useMemo } from 'react';
import { useSmartEditController } from './smart-edit/useSmartEditController';
import { SmartEditHeader } from './smart-edit/SmartEditHeader';
import { SmartEditInfo } from './smart-edit/SmartEditInfo';
import { SmartEditForm } from './smart-edit/SmartEditForm';
import { SmartEditSuggestions } from './smart-edit/SmartEditSuggestions';

export const SmartEditModal: React.FC = () => {
    const ctrl = useSmartEditController();

    const allContributors = useMemo(() => {
        return ctrl.contributorFiles.flatMap(file => {
            const church = ctrl.churches.find((c: any) => c.id === file.churchId);
            return file.contributors?.map(c => ({
                ...c, _churchName: church?.name || 'Desconhecida', _churchId: church?.id
            })) || [];
        });
    }, [ctrl.contributorFiles, ctrl.churches]);

    const availableBankTransactions = useMemo(() => {
        return ctrl.matchResults.filter((r: any) => r.status === 'NÃO IDENTIFICADO');
    }, [ctrl.matchResults]);

    if (!ctrl.smartEditTarget) return null;

    return (
        <div className="glass-overlay animate-fade-in">
            <div 
                ref={ctrl.modalRef} 
                style={{ 
                    position: ctrl.position ? 'fixed' : 'relative', 
                    left: ctrl.position ? ctrl.position.x : 'auto', 
                    top: ctrl.position ? ctrl.position.y : 'auto', 
                    zIndex: 100, 
                    transform: ctrl.position ? 'none' : undefined 
                }} 
                className="glass-modal w-[320px] flex flex-col max-h-[550px] animate-scale-in rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 bg-white/95 dark:bg-slate-900/95"
            >
                <SmartEditHeader 
                    isReverseMode={ctrl.isReverseMode} 
                    onMouseDown={ctrl.handleMouseDown} 
                    onClose={ctrl.closeSmartEdit} 
                />

                <SmartEditInfo 
