import React, { useState, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';

export const useAuthController = () => {
    const [isLogin, setIsLogin] = useState(true);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [message, setMessage] = useState<string | null>(null);

    const toggleMode = useCallback(() => {
        setIsLogin(prev => !prev);
        setError(null);
        setMessage(null);
    }, []);

    const handleGoogleLogin = async () => {
        setLoading(true);
        setError(null);
        try {
            const { error } = await (supabase.auth as any).signInWithOAuth({
                provider: 'google',
                options: {
                    queryParams: {
                        access_type: 'offline',
                        prompt: 'consent',
                    },
                    redirectTo: window.location.origin
                },
            });
            if (error) throw error;
        } catch (err: any) {
            console.error("Google login error:", err);
            setError(err.message === 'Failed to fetch' 
                ? 'O servidor está acordando. Aguarde alguns segundos e tente novamente.' 
                : (err.message || 'Erro ao conectar com Google.'));
            setLoading(false);
        }
    };

    // Fix: Added React to imports and typed event as React.FormEvent
    const handleAuth = async (event: React.FormEvent) => {
        event.preventDefault();
        setLoading(true);
        setError(null);
        setMessage(null);

        if (password.length < 6) {
            setError('A senha precisa ter no mínimo 6 caracteres.');
            setLoading(false);
            return;
        }

        let attempts = 0;
        const maxAttempts = 3;
        let success = false;

        while (attempts < maxAttempts && !success) {
            attempts++;
            try {
                if (isLogin) {
                    const { error } = await (supabase.auth as any).signInWithPassword({ email, password });
                    if (error) throw error;
                } else {
                    const { error } = await (supabase.auth as any).signUp({
                        email,
                        password,
                        options: { data: { full_name: name } }
                    });
                    if (error) throw error;
                    setMessage('Cadastro realizado! Verifique seu email para confirmação.');
                }
                success = true;
            } catch (err: any) {
                if (attempts === maxAttempts) {
                    if (err.message === 'Failed to fetch' || err.message.includes('NetworkError')) {
                        setError('O servidor está demorando para responder (Cold Start). Aguarde 10 segundos e tente novamente.');
                    } else if (err.message.includes('Invalid login credentials')) {
                        setError('Email ou senha incorretos.');
                    } else {
                        setError(err.message || 'Ocorreu um erro inesperado.');
                    }
                } else {
                    await new Promise(resolve => setTimeout(resolve, 2000));
                }
            }
        }
        setLoading(false);
    };

    return {
        isLogin, name, setName, email, setEmail, password, setPassword,
        showPassword, setShowPassword, loading, error, message,
        toggleMode, handleGoogleLogin, handleAuth
    };
};

import React, { useState, useEffect, useRef, useContext, useCallback } from 'react';
import { AppContext } from '../../../contexts/AppContext';

export type AutoLaunchStep = 'choice' | 'teaching' | 'executing';

export const useAutoLaunchController = () => {
    const { 
        autoLaunchTarget, 
        closeAutoLaunch, 
        markAsLaunched, 
        automationMacros, 
        fetchMacros 
    } = useContext(AppContext);

    const [step, setStep] = useState<AutoLaunchStep>('choice');
    const [currentIndex, setCurrentIndex] = useState(0);
    const [isRefreshing, setIsRefreshing] = useState(false);

    // Draggable State
    const [position, setPosition] = useState<{x: number, y: number} | null>(null);
    const [isDragging, setIsDragging] = useState(false);
    const dragStart = useRef<{x: number, y: number}>({ x: 0, y: 0 });
    const modalRef = useRef<HTMLDivElement>(null);

    const currentItem = autoLaunchTarget ? autoLaunchTarget[currentIndex] : null;
    const isFinished = autoLaunchTarget ? currentIndex >= autoLaunchTarget.length : true;
    const activeMacro = automationMacros && automationMacros.length > 0 ? automationMacros[0] : null;

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await fetchMacros();
        setIsRefreshing(false);
    };

    // Fix: Added React to imports and typed event as React.MouseEvent
    const handleMouseDown = (e: React.MouseEvent) => {
        if (modalRef.current) {
            setIsDragging(true);
            const rect = modalRef.current.getBoundingClientRect();
            dragStart.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
        }
    };

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (isDragging) {
                const newX = e.clientX - dragStart.current.x;
                const newY = e.clientY - dragStart.current.y;
                setPosition({ x: newX, y: newY });
            }
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging]);

    const startTeaching = () => {
        if (!currentItem) return;
        const sample = {
            id: currentItem.transaction.id,
            name: currentItem.contributor?.name || currentItem.transaction.description,
            amount: currentItem.transaction.amount,
            date: currentItem.transaction.date,
            church: currentItem.church?.name
        };

        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "START_TRAINING", 
            payload: { bankName: "Sistema Alvo", sampleItem: sample } 
        }, "*");
        setStep('teaching');
    };

    const stopTrainingAndSave = () => {
        window.postMessage({ source: "IdentificaPixIA", type: "STOP_TRAINING" }, "*");
        setStep('choice');
        setCurrentIndex(0);
        setTimeout(handleRefresh, 2000);
    };

    const sendCurrentToExtension = useCallback(() => {
        if (!currentItem || !activeMacro) return;
        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "EXECUTE_ITEM", 
            payload: { 
                macro: activeMacro,
                data: { 
                    id: currentItem.transaction.id,
                    date: currentItem.transaction.date,
                    name: currentItem.contributor?.name || currentItem.transaction.description,
                    amount: currentItem.transaction.amount,
                    church: currentItem.church?.name
                } 
            } 
        }, "*");
    }, [currentItem, activeMacro]);

    const confirmCurrentLaunch = useCallback(() => {
        if (!currentItem || !autoLaunchTarget) return;
        const id = currentItem.transaction.id;
        markAsLaunched(id);
        if (currentIndex < autoLaunchTarget.length - 1) {
            setCurrentIndex(prev => prev + 1);
        } else {
            setCurrentIndex(autoLaunchTarget.length);
        }
    }, [currentItem, autoLaunchTarget, currentIndex, markAsLaunched]);

    const startExecution = () => {
        if (!activeMacro) return;
        setStep('executing');
        sendCurrentToExtension();
    };

    const handleManualLaunchAll = () => {
        if (!autoLaunchTarget) return;
        autoLaunchTarget.forEach(item => markAsLaunched(item.transaction.id));
        closeAutoLaunch();
    };

    useEffect(() => {
        if (step === 'executing' && !isFinished) {
            const timer = setTimeout(sendCurrentToExtension, 1500);
            return () => clearTimeout(timer);
        }
    }, [currentIndex, step, isFinished, sendCurrentToExtension]);

    useEffect(() => {
        const handleExtensionMessage = (event: MessageEvent) => {
            if (event.data?.source !== "IdentificaPixExt") return;
            if (event.data?.type === "ITEM_DONE" || event.data?.type === "AUTO_SUCCESS") {
                if (step === 'executing') confirmCurrentLaunch();
            }
        };
        window.addEventListener("message", handleExtensionMessage);
        return () => window.removeEventListener("message", handleExtensionMessage);
    }, [step, confirmCurrentLaunch]);

    return {
        autoLaunchTarget, closeAutoLaunch, step, setStep, currentIndex, setCurrentIndex,
        isRefreshing, handleRefresh, position, handleMouseDown, modalRef,
        currentItem, isFinished, activeMacro, startTeaching, stopTrainingAndSave,
        startExecution, handleManualLaunchAll
    };
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { supabase } from '../../services/supabaseClient';
import { useUI } from '../../contexts/UIContext';

export const useAdminUsers = () => {
    const { showToast } = useUI();
    const [usersList, setUsersList] = useState<any[]>([]);
    const [isLoadingData, setIsLoadingData] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    // Edit State
    const [editingUser, setEditingUser] = useState<any | null>(null);
    const [formData, setFormData] = useState({
        subscription_status: 'trial',
        limit_ai: 100,
        usage_ai: 0,
        max_churches: 2,
        custom_price: '',
        is_blocked: false,
        trial_ends_at: '',
        subscription_ends_at: ''
    });
    const [isSaving, setIsSaving] = useState(false);

    const fetchUsers = useCallback(async () => {
        setIsLoadingData(true);
        try {
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .order('created_at', { ascending: false });

            if (error) throw error;
            setUsersList(data || []);
        } catch (error: any) {
            console.error("Erro ao buscar usuários:", error);
            showToast("Erro ao carregar usuários: " + error.message, "error");
        } finally {
            setIsLoadingData(false);
        }
    }, [showToast]);

    useEffect(() => {
        fetchUsers();
    }, [fetchUsers]);

    const handleEditClick = useCallback((user: any) => {
        setEditingUser(user);
        const formatDate = (dateStr: string) => dateStr ? new Date(dateStr).toISOString().split('T')[0] : '';

        setFormData({
            subscription_status: user.subscription_status || 'trial',
            limit_ai: user.limit_ai || 100,
            usage_ai: user.usage_ai || 0,
            max_churches: user.max_churches || 1,
            custom_price: user.custom_price || '',
            is_blocked: user.is_blocked || false,
            trial_ends_at: formatDate(user.trial_ends_at),
            subscription_ends_at: formatDate(user.subscription_ends_at)
        });
    }, []);

    // Fix: Added React to imports and typed event as React.FormEvent
    const handleSaveUser = useCallback(async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editingUser) return;
        setIsSaving(true);

        try {
            const updates: any = {
                subscription_status: formData.subscription_status,
                limit_ai: parseInt(String(formData.limit_ai)),
                usage_ai: parseInt(String(formData.usage_ai)),
                max_churches: parseInt(String(formData.max_churches)),
                max_banks: parseInt(String(formData.max_churches)),
                custom_price: formData.custom_price ? parseFloat(String(formData.custom_price)) : null,
                is_blocked: formData.is_blocked,
                is_lifetime: formData.subscription_status === 'lifetime'
            };

            if (formData.trial_ends_at) updates.trial_ends_at = new Date(formData.trial_ends_at).toISOString();
            if (formData.subscription_ends_at) updates.subscription_ends_at = new Date(formData.subscription_ends_at).toISOString();

            const { error } = await supabase
                .from('profiles')
                .update(updates)
                .eq('id', editingUser.id);

            if (error) throw error;

            showToast("Usuário atualizado com sucesso!", "success");
            setEditingUser(null);
            fetchUsers(); 
        } catch (error: any) {
            console.error("Erro ao atualizar:", error);
            showToast("Erro ao salvar: " + error.message, "error");
        } finally {
            setIsSaving(false);
        }
    }, [editingUser, formData, fetchUsers, showToast]);

    const filteredUsers = useMemo(() => {
        return usersList.filter(u => 
            (u.email || '').toLowerCase().includes(searchTerm.toLowerCase()) || 
            (u.name || '').toLowerCase().includes(searchTerm.toLowerCase())
        );
    }, [usersList, searchTerm]);

    return {
        usersList: filteredUsers,
        isLoadingData,
        searchTerm,
        setSearchTerm,
        editingUser,
        setEditingUser,
        formData,
        setFormData,
        isSaving,
        handleEditClick,
        handleSaveUser,
        fetchUsers
    };
};

import React, { useState, useContext, useCallback, useMemo, useEffect, useRef } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { supabase } from '../services/supabaseClient';
import { MatchResult, SpreadsheetData, ManualRow, ColumnDef } from '../types';
import { analysisProcessor, SortConfig } from '../services/analysisProcessor';
import { rankingService } from '../services/rankingService';
import { PLACEHOLDER_CHURCH, groupResultsByChurch } from '../services/processingService';

export const useSmartAnalysisController = () => {
    const { t } = useTranslation();
    const { 
        matchResults, setMatchResults, setReportPreviewData, setHasActiveSession,
        savedReports, openSaveReportModal, activeSpreadsheetData, activeReportId,
        setActiveReportId, overwriteSavedReport, churches 
    } = useContext(AppContext);
    const { showToast, setIsLoading } = useUI();

    const [activeTemplate, setActiveTemplate] = useState<'ranking' | 'manual_structure'>('ranking');
    const [reportTitle, setReportTitle] = useState('Relatório Financeiro');
    const [reportLogo, setReportLogo] = useState<string | null>(null);
    const [signatures, setSignatures] = useState<string[]>(['Tesoureiro', 'Pastor Responsável']);
    const [manualRows, setManualRows] = useState<ManualRow[]>([]);
    const [isRankingLoading, setIsRankingLoading] = useState(false);
    const [columns, setColumns] = useState<ColumnDef[]>(analysisProcessor.createDefaultColumns());
    const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
    const [sumModal, setSumModal] = useState<{ isOpen: boolean, rowId: string, colId: string, currentValue: number } | null>(null);
    const [sumValue, setSumValue] = useState('');
    const [showReportSelector, setShowReportSelector] = useState(false);

    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (activeSpreadsheetData && activeReportId) {
            setManualRows(activeSpreadsheetData.rows);
            setColumns(activeSpreadsheetData.columns);
            setReportTitle(activeSpreadsheetData.title);
            setSignatures(activeSpreadsheetData.signatures || []);
            setReportLogo(activeSpreadsheetData.logo);
            setActiveTemplate('manual_structure');
        }
    }, [activeSpreadsheetData, activeReportId]);

    const generateRankingFromData = useCallback((data: MatchResult[], reportName: string) => {
        setIsRankingLoading(true);
        setManualRows([]);
        setTimeout(() => {
            try {
                const { rows, columns: cols, title } = rankingService.generateRanking(data, churches, reportName);
                setColumns(cols);
                setManualRows(rows);
                setReportTitle(title);
                setActiveTemplate('ranking');
                if (rows.length === 0) showToast("Relatório vazio ou sem dados para ranking.", "error");
            } catch (error) {
                showToast("Erro ao processar dados para o ranking.", "error");
            } finally { setIsRankingLoading(false); }
        }, 50); 
    }, [churches, showToast]);

    const handleRankingClick = () => {
        if (matchResults.length > 0) {
            generateRankingFromData(matchResults, activeReportId ? '' : 'Sessão Atual');
        } else {
            setShowReportSelector(true);
        }
    };

    const handleManualClick = () => {
        if (activeReportId) setActiveReportId(null);
        setActiveTemplate('manual_structure');
        setManualRows([]);
        setReportTitle("Relatório Manual");
        setColumns(analysisProcessor.createDefaultColumns());
        showToast("Nova planilha criada.", "success");
    };

    const handleSelectReport = async (report: any) => {
        setShowReportSelector(false);
        setIsLoading(true);
        try {
            let results = report.data?.results;
            if (!results) {
                const { data } = await supabase.from('saved_reports').select('data').eq('id', report.id).single();
                const parsedData = typeof data?.data === 'string' ? JSON.parse(data.data) : data?.data;
                results = parsedData?.results;
            }
            if (results?.length > 0) {
                const hydrated = results.map((r: any) => ({ 
                    ...r, 
                    church: churches.find((c: any) => c.id === (r.church?.id || r._churchId)) || r.church || PLACEHOLDER_CHURCH 
                }));
                setMatchResults(hydrated);
                setReportPreviewData({
                    income: groupResultsByChurch(hydrated.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': hydrated.filter((r: any) => r.transaction.amount < 0) }
                });
                setActiveReportId(report.id);
                setHasActiveSession(true);
                generateRankingFromData(hydrated, report.name);
                showToast(`Relatório "${report.name}" carregado.`, "success");
            } else { showToast("Relatório vazio.", "error"); }
        } catch (error: any) { 
            showToast("Erro ao processar relatório.", "error"); 
        } finally { setIsLoading(false); }
    };

    // Fix: Added React to imports and typed event as React.ChangeEvent
    const handleLogoUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => setReportLogo(e.target?.result as string);
            reader.readAsDataURL(file);
        }
    };

    const handleSave = () => {
        const data: SpreadsheetData = { title: reportTitle, logo: reportLogo, columns, rows: manualRows, signatures };
        if (activeReportId) overwriteSavedReport(activeReportId, [], data);
        else openSaveReportModal({ type: 'spreadsheet', groupName: reportTitle, spreadsheetData: data, results: [] });
    };

    const sortedRows = useMemo(() => analysisProcessor.sortRows(manualRows, sortConfig), [manualRows, sortConfig]);
    const summaryData = useMemo(() => analysisProcessor.calculateSummary(manualRows), [manualRows]);

    return {
        activeTemplate, setActiveTemplate, reportTitle, setReportTitle, reportLogo, signatures, setSignatures,
        manualRows, setManualRows, isRankingLoading, columns, setColumns, sortConfig, setSortConfig,
        sumModal, setSumModal, sumValue, setSumValue, showReportSelector, setShowReportSelector,
        fileInputRef, handleRankingClick, handleManualClick, handleSelectReport, handleLogoUpload,
        handleSave, sortedRows, summaryData, savedReports, activeReportId
    };
};

import React, { useState, useEffect, useMemo, useRef, useContext, useCallback } from 'react';
import { AppContext } from '../../../contexts/AppContext';
import { useTranslation } from '../../../contexts/I18nContext';
import { calculateNameSimilarity, normalizeString, parseDate } from '../../../services/processingService';
import { Contributor, MatchResult, ReconciliationStatus, MatchMethod } from '../../../types';

export interface SuggestionItem {
    id: string;
    primaryText: string;
    secondaryText: string;
    amount: number;
    date?: string;
    originalRef: any;
    score: number;
    type: 'contributor' | 'transaction';
    isAiSuggestion?: boolean;
    contributionType?: string;
    paymentMethod?: string;
    churchId?: string;
}

export const useSmartEditController = () => {
    const { 
        smartEditTarget, closeSmartEdit, saveSmartEdit, contributorFiles, churches,
        matchResults, effectiveIgnoreKeywords, contributionKeywords, paymentMethods,
        aiSuggestion, loadingAiId
    } = useContext(AppContext);
    const { language } = useTranslation();

    const [searchQuery, setSearchQuery] = useState('');
    const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
    const [manualName, setManualName] = useState('');
    const [manualAmount, setManualAmount] = useState('');
    const [manualChurchId, setManualChurchId] = useState('');
    const [manualType, setManualType] = useState('');
    const [manualPaymentMethod, setManualPaymentMethod] = useState('');
    const [isManualMode, setIsManualMode] = useState(false);

    const [position, setPosition] = useState<{x: number, y: number} | null>(null);
    const [isDragging, setIsDragging] = useState(false);
    const dragStart = useRef<{x: number, y: number}>({ x: 0, y: 0 });
    const modalRef = useRef<HTMLDivElement>(null);

    const isReverseMode = useMemo(() => smartEditTarget?.status === ReconciliationStatus.PENDING, [smartEditTarget]);
    const isAiProposed = useMemo(() => !!smartEditTarget?.suggestion || !!aiSuggestion, [smartEditTarget, aiSuggestion]);

    // Keyboard shortcuts
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'Escape') closeSmartEdit();
            if (e.key === 'Enter' && !isManualMode && suggestions.length > 0 && !searchQuery) {
                const topSug = suggestions[0];
                if (topSug.churchId === manualChurchId) handleSelect(topSug);
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [closeSmartEdit, isManualMode, suggestions, searchQuery, manualChurchId]);

    // Data initialization
    useEffect(() => {
        if (smartEditTarget) {
            setSearchQuery('');
            const nameToEdit = smartEditTarget.contributor?.cleanedName || smartEditTarget.contributor?.name || smartEditTarget.transaction.cleanedDescription || '';
            const amountToEdit = String(smartEditTarget.contributor?.amount || smartEditTarget.transaction.amount);
            const sug = smartEditTarget.suggestion as any;

            setManualName(nameToEdit);
            setManualAmount(amountToEdit);
            setManualType(sug?.contributionType || smartEditTarget.contributor?.contributionType || smartEditTarget.transaction.contributionType || '');
            setManualPaymentMethod(sug?.paymentMethod || smartEditTarget.contributor?.paymentMethod || smartEditTarget.transaction.paymentMethod || '');

            const churchIdToEdit = sug?._churchId || sug?.church?.id || smartEditTarget.church?.id;
            if (isReverseMode && smartEditTarget.church) setManualChurchId(smartEditTarget.church.id);
            else if (churchIdToEdit && churchIdToEdit !== 'unidentified' && churchIdToEdit !== 'placeholder') setManualChurchId(churchIdToEdit);
            else setManualChurchId(churches.length === 1 ? churches[0].id : '');

            setIsManualMode(false);
            setPosition(null);
        }
    }, [smartEditTarget, isReverseMode, churches]);

    // Fix: Added React to imports and typed event as React.MouseEvent
    const handleMouseDown = (e: React.MouseEvent) => {
        if (modalRef.current) {
            setIsDragging(true);
            const rect = modalRef.current.getBoundingClientRect();
            dragStart.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
        }
    };

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (isDragging) setPosition({ x: e.clientX - dragStart.current.x, y: e.clientY - dragStart.current.y });
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging]);

    const handleSelect = (item: SuggestionItem) => {
        if (isReverseMode) {
            const targetMatchResult = item.originalRef as MatchResult;
            saveSmartEdit({ ...targetMatchResult, contributor: smartEditTarget.contributor, church: smartEditTarget.church, status: ReconciliationStatus.IDENTIFIED, matchMethod: MatchMethod.MANUAL, similarity: 100, contributorAmount: smartEditTarget.contributor?.amount, divergence: undefined, contributionType: manualType || smartEditTarget.contributor?.contributionType, paymentMethod: manualPaymentMethod || smartEditTarget.contributor?.paymentMethod });
        } else {
            const selectedContributor = item.originalRef;
            saveSmartEdit({ ...smartEditTarget, contributor: selectedContributor, church: churches.find((c: any) => c.id === selectedContributor._churchId) || smartEditTarget.church, status: ReconciliationStatus.IDENTIFIED, matchMethod: item.isAiSuggestion ? MatchMethod.AI : MatchMethod.MANUAL, similarity: 100, contributorAmount: selectedContributor.amount, divergence: undefined, contributionType: manualType || selectedContributor.contributionType, paymentMethod: manualPaymentMethod || selectedContributor.paymentMethod });
        }
    };

    const handleSaveManual = () => {
        const amount = parseFloat(manualAmount);
        if (!manualName.trim() || isNaN(amount)) return;
        saveSmartEdit({ 
            ...smartEditTarget, 
            contributor: { id: `man-${Date.now()}`, name: manualName, cleanedName: manualName, normalizedName: normalizeString(manualName), amount, date: smartEditTarget.contributor?.date || smartEditTarget.transaction.date, contributionType: manualType, paymentMethod: manualPaymentMethod }, 
            church: churches.find((c: any) => c.id === manualChurchId) || smartEditTarget.church, 
            status: ReconciliationStatus.IDENTIFIED, matchMethod: MatchMethod.MANUAL, similarity: 100, contributorAmount: amount, divergence: undefined, contributionType: manualType, paymentMethod: manualPaymentMethod 
        });
    };

    return {
        smartEditTarget, closeSmartEdit, suggestions, setSuggestions, searchQuery, setSearchQuery,
        manualName, setManualName, manualAmount, setManualAmount, manualChurchId, setManualChurchId,
        manualType, setManualType, manualPaymentMethod, setManualPaymentMethod,
        handleSelect, handleSaveManual, position, handleMouseDown, modalRef, language,
        isReverseMode, isAiProposed, churches, loadingAiId, contributionKeywords, paymentMethods,
        effectiveIgnoreKeywords, matchResults, contributorFiles
    };
};

import React, { useState, useCallback, useRef } from 'react';
import { supabase } from '../../services/supabaseClient';
import { SubscriptionStatus } from '../../types';
import { SystemSettings } from './AuthContracts';

// Fix: Added React to imports and typed settingsRef as React.MutableRefObject
export const useSubscriptionState = (settingsRef: React.MutableRefObject<SystemSettings>) => {
    const [subscription, setSubscription] = useState<SubscriptionStatus>({
        plan: 'trial',
        daysRemaining: 10,
        totalDays: 10,
        isExpired: false,
        isBlocked: false,
        isLifetime: false,
        aiLimit: 100, 
        aiUsage: 0,
        maxChurches: 2, 
        maxBanks: 2
    });

    const lastProcessedUserId = useRef<string | null>(null);

    const calculateSubscription = useCallback(async (userId: string | null, force: boolean = false) => {
        if (!userId) return;
        if (!force && lastProcessedUserId.current === userId) return;

        lastProcessedUserId.current = userId;
        const settings = settingsRef.current;

        try {
            const fetchPromise = supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
            const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject(new Error("Timeout")), 15000));

            const { data: profileData } = await Promise.race([fetchPromise, timeoutPromise]) as any;
            const now = new Date();
            const p = (profileData as any) || {};

            const isBlocked = p.is_blocked === true;
            const isLifetime = p.is_lifetime === true || p.subscription_status === 'lifetime';
            let status = p.subscription_status || 'trial';
            let daysRemaining = 0;

            if (isLifetime) {
                status = 'lifetime';
                daysRemaining = 9999;
            } else if (status === 'active' && p.subscription_ends_at) {
                const diff = new Date(p.subscription_ends_at).getTime() - now.getTime();
                daysRemaining = Math.ceil(diff / (1000 * 60 * 60 * 24));
                if (daysRemaining <= 0) { status = 'expired'; daysRemaining = 0; }
            } else {
                const trialEnd = p.trial_ends_at ? new Date(p.trial_ends_at) : new Date(now.getTime() + settings.defaultTrialDays * 86400000);
                const diff = trialEnd.getTime() - now.getTime();
                daysRemaining = Math.ceil(diff / (1000 * 60 * 60 * 24));
                if (daysRemaining <= 0) { status = 'expired'; daysRemaining = 0; }
            }

            setSubscription({
                plan: status as any,
                daysRemaining: Math.max(0, daysRemaining),
                totalDays: status === 'trial' ? settings.defaultTrialDays : 30,
                isExpired: status === 'expired',
                isBlocked,
                isLifetime,
                aiLimit: p.limit_ai || settings.baseAiLimit,
                aiUsage: p.usage_ai || 0,
                maxChurches: p.max_churches || settings.baseSlots,
                maxBanks: p.max_banks || settings.baseSlots
            });
        } catch (e) {
            console.error("Erro assinatura (resgatando padrão):", e);
        }
    }, [settingsRef]);

    return { subscription, setSubscription, calculateSubscription, lastProcessedUserId };
};

import React, { useCallback } from 'react';
import { supabase } from '../../services/supabaseClient';
import { SubscriptionStatus } from '../../types';

export const useAuthActions = (
    user: any, 
    // Fix: Added React to imports and typed setSubscription using React.Dispatch and React.SetStateAction
    setSubscription: React.Dispatch<React.SetStateAction<SubscriptionStatus>>,
    refreshSubscription: () => Promise<void>
) => {
    const addSubscriptionDays = useCallback(async (days: number) => {
        if (!user) return;
        const { data: p } = await supabase.from('profiles').select('subscription_ends_at').eq('id', user.id).single();
        const current = (p as any)?.subscription_ends_at ? new Date((p as any).subscription_ends_at) : new Date();
        const next = new Date(current.getTime() + days * 86400000);
        await supabase.from('profiles').update({ subscription_status: 'active', subscription_ends_at: next.toISOString() }).eq('id', user.id);
        refreshSubscription();
    }, [user, refreshSubscription]);

    const updateLimits = useCallback(async (slots: number, aiPacks: number) => {
        if (!user) return;
        const { data: p } = await supabase.from('profiles').select('limit_ai').eq('id', user.id).single();
        const newLimit = ((p as any)?.limit_ai || 100) + (aiPacks * 1000);
        await supabase.from('profiles').update({ limit_ai: newLimit, max_churches: slots, max_banks: slots }).eq('id', user.id);
        refreshSubscription();
    }, [user, refreshSubscription]);

    const incrementAiUsage = useCallback(async () => {
        if (!user) return;
        setSubscription(s => ({ ...s, aiUsage: (s.aiUsage || 0) + 1 }));
        const { data: p } = await supabase.from('profiles').select('usage_ai').eq('id', user.id).single();
        await supabase.from('profiles').update({ usage_ai: ((p as any)?.usage_ai || 0) + 1 }).eq('id', user.id);
    }, [user, setSubscription]);

    const registerPayment = useCallback(async (amount: number, method: string, notes?: string) => {
        if (!user) return;
        await supabase.from('payments').insert({ user_id: user.id, amount, status: 'approved', notes: notes || `Via ${method}` });
        await addSubscriptionDays(30);
    }, [user, addSubscriptionDays]);

    return { addSubscriptionDays, updateLimits, incrementAiUsage, registerPayment };
};
